1440	Nakayama prolongation producing \(e\)-generator presentations near a point
1441	of fiber rank \(e\).  Throughout, \(R\) is a commutative ring and \(M\) an
1442	\(R\)-module.
1443	
1444	\begin{definition}[Matrix presentation]
1445	  \label{def:matrix_presentation}
1446	  \lean{Module.MatrixPresentation}
1447	  \leanok
1448	  \source{nitsure-hilbert-quot}
1449	  A \emph{matrix presentation} of \(M\) by \(e\) generators and \(m\)
1450	  relations consists of a matrix
1451	  \(\psi \in \operatorname{Mat}_{e \times m}(R)\) and a surjection
1452	  \(\pi : R^{\oplus e} \to M\) making the sequence
1453	  \[
1454	    R^{\oplus m} \xrightarrow{\ \psi\ } R^{\oplus e}
1455	      \xrightarrow{\ \pi\ } M \to 0
1456	  \]
1457	  exact.
1458	\end{definition}
1459	
1460	\begin{lemma}[Finite presentation]
1461	  \label{lem:matrix_presentation_fp}
1462	  \lean{Module.MatrixPresentation.finitePresentation}
1463	  \leanok
1464	  \uses{def:matrix_presentation}
1465	  A module admitting a matrix presentation is finitely presented.
1466	\end{lemma}
1467	
1468	\begin{proof}
1469	  \leanok
1470	  \(\pi\) is a surjection from a finite free module whose kernel, the image
1471	  of \(\psi\), is generated by the \(m\) columns of \(\psi\), hence finitely
1472	  generated.
1473	\end{proof}
1474	
1475	\begin{definition}[Entry ideal]
1476	  \label{def:entry_ideal}
1477	  \lean{Module.MatrixPresentation.entryIdeal}
1478	  \leanok
1479	  \uses{def:matrix_presentation}
1480	  \source{nitsure-hilbert-quot}
1481	  The \emph{entry ideal} \(I(\psi) \subseteq R\) of a matrix presentation is
1482	  the ideal generated by the \(e \cdot m\) entries \(\psi_{ij}\) of the
1483	  relation matrix.  It is the ideal of \(1 \times 1\) minors of \(\psi\);
1484	  for an \(e\)-generator presentation this is the Fitting ideal
1485	  \(\operatorname{Fitt}_{e-1}(M)\).
1486	\end{definition}
1487	
1488	\begin{lemma}[Vanishing criterion]
1489	  \label{lem:entry_ideal_vanish}
1490	  \lean{Module.MatrixPresentation.relMatrix_map_eq_zero_iff}
1491	  \leanok
1492	  \uses{def:entry_ideal}
1493	  For an \(R\)-algebra \(A\), the entrywise image matrix
1494	  \(\psi \otimes A \in \operatorname{Mat}_{e \times m}(A)\) vanishes if and
1495	  only if \(I(\psi) \subseteq \ker(R \to A)\).
1496	\end{lemma}
1497	
1498	\begin{proof}
1499	  \leanok
1500	  Both sides assert that every entry of \(\psi\) maps to \(0\) in \(A\).
1501	\end{proof}
1502	
1503	\begin{definition}[Base change of a presentation]
1504	  \label{def:matrix_presentation_base_change}
1505	  \lean{Module.MatrixPresentation.baseChange}
1506	  \leanok
1507	  \uses{def:matrix_presentation}
1508	  \source{nitsure-hilbert-quot}
1509	  Let \(A\) be an \(R\)-algebra.  The matrix \(\psi \otimes A\) obtained by
1510	  applying \(R \to A\) entrywise, together with the tensored projection
1511	  \(A^{\oplus e} \cong A \otimes_R R^{\oplus e}
1512	    \xrightarrow{1 \otimes \pi} A \otimes_R M\),
1513	  is a matrix presentation of \(A \otimes_R M\) by \(e\) generators and
1514	  \(m\) relations: the tensored sequence
1515	  \(A^{\oplus m} \to A^{\oplus e} \to A \otimes_R M \to 0\) remains exact by
1516	  right-exactness of the tensor product.
1517	\end{definition}
1518	
1519	\begin{lemma}[Entry ideal under base change]
1520	  \label{lem:entry_ideal_base_change}
1521	  \lean{Module.MatrixPresentation.entryIdeal_baseChange}
1522	  \leanok
1523	  \uses{def:entry_ideal, def:matrix_presentation_base_change}
1524	  The entry ideal of the base-changed presentation is the image ideal:
1525	  \(I(\psi \otimes A) = I(\psi) \cdot A\).
1526	\end{lemma}
1527	
1528	\begin{proof}
1529	  \leanok
1530	  The generators of \(I(\psi \otimes A)\) are exactly the images of the
1531	  generators of \(I(\psi)\).
1532	\end{proof}
1533	
1534	\begin{lemma}[Vanishing relations give an isomorphism]
1535	  \label{lem:presentation_iso_of_vanish}
1536	  \lean{Module.MatrixPresentation.projEquiv}
1537	  \leanok
1538	  \uses{def:matrix_presentation}
1539	  If \(\psi = 0\), then \(\pi : R^{\oplus e} \to M\) is an isomorphism.
1540	\end{lemma}
1541	
1542	\begin{proof}
1543	  \leanok
1544	  \(\ker \pi = \operatorname{im} \psi = 0\) by exactness, and \(\pi\) is
1545	  surjective.
1546	\end{proof}
1547	
1548	\begin{lemma}[Vanishing relations give a free module]
1549	  \label{lem:presentation_free_of_vanish}
1550	  \lean{Module.MatrixPresentation.free_of_relMatrix_eq_zero}
1551	  \leanok
1552	  \uses{lem:presentation_iso_of_vanish}
1553	  If \(\psi = 0\), then \(M\) is free.
1554	\end{lemma}
1555	
1556	\begin{proof}
1557	  \leanok
1558	  Transport freeness along the isomorphism of
1559	  \cref{lem:presentation_iso_of_vanish}.

